revision.text:
==TemplateData==
{{TemplateData header}}
<templatedata>
{
	"description": "Starts a succession-box. The box should end with {{S-end}} and can include many other templates in the succession box family including {{s-break}}: breaks, {{s-bef}}: predecessors, {{s-aft}}: successors, {{s-ttl}}: titles and years, {{s-new}}: new titles, {{s-non}}: no successors, {{s-inc}}: For incumbents, {{s-vac}}: vacant titles (predecessor or successor), {{s-tul}}: titular monarchs, {{s-hou}}: royal house/individual information, {{s-ref}}: references, {{s-line}}: rail/subway/underground networks.",
	"params": {
		"noclear": {
			"label": "noclear",
			"description": "If set suppresses the normal clear:both function.",
			"type": "string",
			"required": false
		}
	}
}
</templatedata>

